def validate_integer(value: Any, min_val: int = None, max_val: int = None, field_name: str = "field") -> int:
    """Validate integer input with bounds"""
    try:
        int_value = int(value)
    except (ValueError, TypeError):
        raise SecurityError(f"{field_name} must be a valid integer")
    
    if min_val is not None and int_value < min_val:
        raise SecurityError(f"{field_name} must be at least {min_val}")
    
    if max_val is not None and int_value > max_val:
        raise SecurityError(f"{field_name} must be at most {max_val}")
    
    return int_value


def validate_json_body(req: func.HttpRequest, required_fields: list = None) -> Dict:
    """Validate and parse JSON body"""
    try:
        body = req.get_json()
    except ValueError:
        raise SecurityError("Invalid JSON in request body")
    
    if not isinstance(body, dict):
        raise SecurityError("Request body must be a JSON object")
    
    if required_fields:
        missing_fields = [field for field in required_fields if field not in body]
        if missing_fields:
            raise SecurityError(f"Missing required fields: {', '.join(missing_fields)}")
    
    return body


def secure_response(status_code: int, body: Dict, headers: Dict = None) -> func.HttpResponse:
    """Create secure HTTP response with proper headers"""
    default_headers = {
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'X-XSS-Protection': '1; mode=block',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        'Cache-Control': 'no-store, no-cache, must-revalidate, private',
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, X-API-Key, Authorization',
        'Access-Control-Max-Age': '3600'
    }
    
    if headers:
        default_headers.update(headers)
    
    return func.HttpResponse(
        body=json.dumps(body),
        status_code=status_code,
        headers=default_headers
    )


def error_response(message: str, status_code: int = 400) -> func.HttpResponse:
    """Create error response"""
    return secure_response(status_code, {'error': message, 'success': False})


def security_middleware(require_auth: bool = True):
    """Decorator for security checks"""
    def decorator(func_handler):
        @wraps(func_handler)
        def wrapper(req: func.HttpRequest) -> func.HttpResponse:
            try:
                # Handle preflight OPTIONS request
                if req.method == 'OPTIONS':
                    return secure_response(200, {})
                
                # Validate request size
                validate_request_size(req)
                
                # Validate content type for non-GET requests
                validate_content_type(req)
                
                # Validate API key if required
                if require_auth and not validate_api_key(req):
                    logging.warning(f"Unauthorized access attempt from {req.headers.get('X-Forwarded-For', 'unknown')}")
                    return error_response("Unauthorized - Invalid or missing API key", 401)
                
                # Call the actual handler
                return func_handler(req)
                
            except SecurityError as e:
                logging.warning(f"Security error: {str(e)}")
                return error_response(str(e), 400)
            except Exception as e:
                logging.error(f"Unexpected error: {str(e)}", exc_info=True)
                return error_response("Internal server error", 500)
        
        return wrapper
    return decorator


